Office.onReady((info) => {
    if (info.host === Office.HostType.Excel) {
        window.addEventListener('message', handleMessage);
    }
});

async function handleMessage(event) {
    if (event.data.type === 'applyToExcel') {
        try {
            const parsedData = typeof event.data.data === 'string'
                ? JSON.parse(event.data.data)
                : event.data.data;
            await appendDataToExcel(parsedData);
        } catch (error) {
            console.error('Error handling applyToExcel:', error);
        }
    }
}

async function appendDataToExcel(data) {
    try {
        await Excel.run(async (context) => {
            const range = context.workbook.getSelectedRange();
            range.load("address");
            range.load("rowIndex");
            range.load("columnIndex");
            await context.sync();

            let colDefs, rows;

            if (data.widget && data.widget.last_step && data.widget.last_step.data) {
                colDefs = data.widget.last_step.data.columns;
                rows = data.widget.last_step.data.rows;
            } else {
                console.error('Unexpected data structure:', data);
                return;
            }

            // Build header row from headerName, look up row values by field
            const headers = colDefs.map(col => col.headerName || col.field || '');
            const values = [headers];
            for (const row of rows) {
                values.push(colDefs.map(col => {
                    const field = col.field || col.colId || col.headerName;
                    const value = row[field];
                    if (value === undefined || value === null) return '';
                    return typeof value === 'object' ? JSON.stringify(value) : value;
                }));
            }

            const sheet = range.worksheet;
            const startRow = range.rowIndex;
            const startCol = range.columnIndex;
            const endRow = startRow + values.length - 1;
            const endCol = startCol + headers.length - 1;

            const targetRange = sheet.getRangeByIndexes(startRow, startCol, values.length, headers.length);
            targetRange.values = values;

            // Format header row
            const headerRange = sheet.getRangeByIndexes(startRow, startCol, 1, headers.length);
            headerRange.format.fill.color = "#ADD8E6";
            headerRange.format.font.bold = true;

            // Add borders
            const dataRange = sheet.getRangeByIndexes(startRow, startCol, values.length, headers.length);
            const borders = ["EdgeTop", "EdgeBottom", "EdgeLeft", "EdgeRight", "InsideHorizontal", "InsideVertical"];
            for (const border of borders) {
                dataRange.format.borders.getItem(border).style = "Continuous";
                dataRange.format.borders.getItem(border).weight = "Thin";
            }

            // Auto-fit columns
            targetRange.getEntireColumn().format.autofitColumns();

            await context.sync();
            console.log('Data appended successfully');
        });
    } catch (error) {
        console.error('Error appending data to Excel:', error);
    }
}

window.onerror = function(message, source, lineno, colno, error) {
    console.error('Global error:', message, 'at', source, lineno, colno);
    return true;
};
